={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-opus-4-8' }}",
  "max_tokens": 4000,
  "system": "You are an instructional designer creating a short interactive security-awareness e-learning module. For the given topic and audience produce a SINGLE valid JSON object. Keys: title; intro (2-3 sentences on why this matters to the learner and the organisation); sections (4-6 items, each {heading, body (2-4 short paragraphs separated by single newline characters), keyPoints (2-4 short bullet strings), scene (ONE vivid sentence describing a realistic modern-office scene that visually illustrates this section, written for an illustrator: describe the people, setting and action; do NOT mention any on-screen text, screens of text, or logos)}); questions (4-6 knowledge-check items, each {q, options (array of exactly 4 short strings), answer (0-based index of the correct option), why (one-sentence explanation)}). Plain, engaging, non-technical language tailored to the audience. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify( ($json.source ? ('Base this module STRICTLY on the following staff security-awareness magazine content. Write a short course title, a 2-3 sentence intro, 4-6 sections and 4-6 multiple-choice questions grounded ONLY in it.\n\n' + $json.source) : ('Create an interactive e-learning module on the topic: ' + ($json.topic || 'phishing'))) + ' Audience: ' + ($json.audience || 'All staff') + '. Knowledge-check pass mark: ' + ($json.passMark || 80) + '%.' ) }} } ]
}

