const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
const STYLE = 'Cinematic, semi-realistic editorial illustration set in a bright modern corporate office. Polished, professional and calm mood; soft natural window light with a warm key light; teal and deep-navy colour grade; shallow depth of field; clean wide composition with generous empty space near the top. Diverse professional people in business-casual attire, natural expressions. ';
const NEG = ' No text, no words, no letters, no numbers, no logos, no signage, no watermark, no user-interface screenshots, no charts.';
if (data && !data.title && r.title) data.title = r.title;
const sections = (data && data.sections) || [];
const imagePrompts = sections.map(function(s){ var scene = (s && (s.scene || s.heading)) || ('a workplace scene about ' + (r.topic||'security awareness')); return STYLE + 'Scene: ' + scene + '.' + NEG; });
const coverPrompt = 'Wide cinematic hero cover image for a premium corporate security-awareness course about ' + (r.topic||'security awareness') + '. ' + STYLE + 'Establishing wide shot of a modern office that conveys trust, focus and vigilance; dramatic but professional lighting; strong empty space on the left for a title.' + NEG;
return [{ json: { data:data, topic:r.topic, audience:r.audience, passMark:r.passMark, format:r.format, illustrate:r.illustrate, imagePrompts:imagePrompts, coverPrompt:coverPrompt, date:r.date, client:r.client, publicationId:r.publicationId, courseId:r.courseId } }];

const j = $json || {};
const sectionPrompts = j.imagePrompts || [];
const coverPrompt = j.coverPrompt || '';
let sections = sectionPrompts.map(function(){ return ''; });
let cover = '';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
if (j.illustrate && key) {
  const H = this.helpers;
  const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
  const model = ($env.IMAGE_MODEL || 'gpt-image-1');
  const size = ($env.ELEARNING_IMAGE_SIZE || '1536x1024');
  const gen = async function(p){
    try {
      const resp = await H.httpRequest({ method:'POST', url: base + '/images/generations',
        headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
        body: { model: model, prompt: p, size: size, n: 1 }, json: true, timeout: 180000 });
      const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
      return b64 ? ('data:image/png;base64,' + b64) : '';
    } catch (e) { return ''; }
  };
  if (coverPrompt) cover = await gen(coverPrompt);
  for (let k = 0; k < sectionPrompts.length; k++) { sections[k] = await gen(sectionPrompts[k]); }
}
return [{ json: Object.assign({}, j, { images: { cover: cover, sections: sections } }) }];

// E-learning renderer — 16:9 enterprise lesson player with cover, name entry,
// section heroes (Ken Burns), animated SVG accents, animated score ring, and a
// bedded-in completion certificate (client-side, print/save-as-PDF). SCORM-aware.
const d = $json.data || {};
const topic = $json.topic || 'Security Awareness';
const date = $json.date || new Date().toISOString().slice(0,10);
const client = ($json.client || '').toString();
const passMark = Number($json.passMark) || 80;
const format = $json.format || 'Both';
const images = ($json.images && typeof $json.images === 'object' && !Array.isArray($json.images))
  ? { cover: ($json.images.cover||''), sections: ($json.images.sections||[]) }
  : { cover:'', sections:(Array.isArray($json.images)?$json.images:[]) };
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const title = d.title || (topic + ' — Awareness Module');
const brand = client ? client : 'Security Awareness';
// Learning Hub: ids that tie a completed course back to its publication card on
// the dashboard (passed in by the orchestrator; empty for standalone runs).
const publicationId = ($json.publicationId || '').toString();
const courseId = ($json.courseId || '').toString();

// --- animated SVG icon set (stroke = brand teal; .pz group is animated in CSS) ---
function ic(inner){ return '<svg viewBox="0 0 24 24" fill="none" stroke="#0E7C86" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><g class="pz">'+inner+'</g></svg>'; }
const ICONS = {
  shield: ic('<path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/>'),
  lock:   ic('<rect x="5" y="11" width="14" height="9" rx="2"/><path d="M8 11V8a4 4 0 0 1 8 0v3"/>'),
  mail:   ic('<rect x="3" y="5" width="18" height="14" rx="2"/><path d="M3 7l9 6 9-6"/>'),
  eye:    ic('<path d="M2 12s4-7 10-7 10 7 10 7-4 7-10 7S2 12 2 12z"/><circle cx="12" cy="12" r="3"/>'),
  alert:  ic('<path d="M12 3l9 16H3z"/><path d="M12 10v4"/><circle cx="12" cy="16.7" r="0.6" fill="#0E7C86" stroke="none"/>'),
  key:    ic('<circle cx="8" cy="12" r="4"/><path d="M12 12h9M18 12v4M21 12v3"/>'),
  phone:  ic('<path d="M6 3h4l2 5-3 2a11 11 0 0 0 5 5l2-3 5 2v4a2 2 0 0 1-2 2A17 17 0 0 1 4 6a2 2 0 0 1 2-3z"/>'),
  id:     ic('<rect x="3" y="5" width="18" height="14" rx="2"/><circle cx="9" cy="11" r="2"/><path d="M14 10h4M14 13h4M6 16h8"/>'),
  check:  ic('<path d="M5 13l4 4 10-10"/>')
};
function pickIcon(h){ h=(h||'').toLowerCase();
  if(/phish|email|mail|bec|message|invoice/.test(h)) return 'mail';
  if(/password|mfa|auth|credential|key|login/.test(h)) return 'key';
  if(/call|phone|vish|voice/.test(h)) return 'phone';
  if(/pretext|imperson|identity|profile/.test(h)) return 'id';
  if(/spot|sign|watch|red flag|detect|recognis|recogniz/.test(h)) return 'eye';
  if(/report|incident|respond|attack|suspect|breach|fraud/.test(h)) return 'alert';
  if(/lock|secure|encrypt|device|protect|data/.test(h)) return 'lock';
  return 'shield';
}
const sections = (d.sections||[]).map(function(s){ var o=Object.assign({}, s); o.iconKey=pickIcon((s.heading||'')+' '+(s.scene||'')); return o; });

// --- premium certificate furniture (gold seal/stamp, corner flourishes, crest, watermark) ---
function certInitials(s){ var w=String(s||'').trim().split(/\s+/).filter(Boolean); var a=(w[0]||'S')[0]+((w[1]||w[0]||'A')[0]||''); return a.toUpperCase().slice(0,2); }
function makeSeal(init, topText, botText){
  var cx=110, cy=104, spikes=30, R1=96, R2=86, pts=[];
  for(var i=0;i<spikes*2;i++){ var r=(i%2===0)?R1:R2; var a=(Math.PI/spikes)*i - Math.PI/2; pts.push((cx+r*Math.cos(a)).toFixed(1)+','+(cy+r*Math.sin(a)).toFixed(1)); }
  var burst='<polygon points="'+pts.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="1"/>';
  function laurel(side){ var g='',n=8; for(var i=0;i<n;i++){ var t=i/(n-1); var ang=(-150 + t*120)*Math.PI/180; var rad=58; var x=cx + side*(rad*Math.cos(ang)*0.62 + 6); var y=cy + 30 - rad*Math.sin(ang)*0.95; var rot=(side>0?-50:50)+(t*60*side); g+='<ellipse cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" rx="9" ry="3.6" fill="#E3C766" transform="rotate('+rot.toFixed(1)+' '+x.toFixed(1)+' '+y.toFixed(1)+')"/>'; } return g; }
  function star(scx,scy,R,r,p2){ var p=[]; for(var i=0;i<p2*2;i++){ var rr=(i%2===0)?R:r; var a=(Math.PI/p2)*i - Math.PI/2; p.push((scx+rr*Math.cos(a)).toFixed(1)+','+(scy+rr*Math.sin(a)).toFixed(1)); } return '<polygon points="'+p.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="0.6"/>'; }
  return '<svg class="seal" viewBox="0 0 220 250" xmlns="http://www.w3.org/2000/svg">'
   +'<defs><radialGradient id="gold" cx="50%" cy="36%" r="68%"><stop offset="0" stop-color="#F6E6A8"/><stop offset="50%" stop-color="#D9B45A"/><stop offset="100%" stop-color="#A9842F"/></radialGradient></defs>'
   +'<path d="M83 150 L70 244 L98 222 L110 240 L122 222 L150 244 L137 150 Z" fill="#0E7C86"/>'
   +'<path d="M83 150 L78 186 L137 186 L137 150 Z" fill="#0a5b63"/>'
   +burst
   +'<circle cx="'+cx+'" cy="'+cy+'" r="80" fill="url(#gold)"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="#0E2233"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="none" stroke="#E3C766" stroke-width="2" stroke-dasharray="1.5 5"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="60" fill="none" stroke="#C9A24B" stroke-width="1"/>'
   +laurel(-1)+laurel(1)+star(cx,cy-18,16,7,5)
   +'<text x="'+cx+'" y="'+(cy+14)+'" text-anchor="middle" font-family="Georgia,serif" font-size="20" font-weight="bold" fill="#F6E6A8" letter-spacing="1">'+esc(init)+'</text>'
   +'<text x="'+cx+'" y="'+(cy+34)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="8.5" fill="#E3C766" letter-spacing="2">'+esc(botText)+'</text>'
   +'<text x="'+cx+'" y="'+(cy-44)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="9" fill="#E3C766" letter-spacing="3">'+esc(topText)+'</text>'
   +'</svg>';
}
function makeCorner(cls){ return '<svg class="cn '+cls+'" viewBox="0 0 80 80"><path d="M6 74 C6 36 36 6 74 6" fill="none" stroke="#C9A24B" stroke-width="2"/><path d="M14 74 C14 42 42 14 74 14" fill="none" stroke="#C9A24B" stroke-width="1"/><circle cx="6" cy="74" r="3.5" fill="#C9A24B"/></svg>'; }
const certSeal = makeSeal(certInitials(brand), 'CERTIFIED', 'EXCELLENCE');
const certCorners = makeCorner('tl')+makeCorner('tr')+makeCorner('bl')+makeCorner('br');
const certCrest = '<svg class="crest" viewBox="0 0 24 24" fill="none" stroke="#0E7C86" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';
